(window.webpackJsonp=window.webpackJsonp||[]).push([[191],{818:function(n,r){n.exports="\x3c!--\r\ntitle: 08-网络\r\nsort:\r\n--\x3e \r\n\r\n> 网络\r\n\r\n## 常用命令\r\n\r\n### ping\r\n\r\n> 发送 `ICMP ECHO_REQUEST`到主机\r\n\r\n### tracepath\r\n\r\n> `tracerote`\r\n>\r\n> 显示本地到服务器的跳数\r\n\r\n### ftp\r\n\r\n| 命令         | 含义             |\r\n| ------------ | ---------------- |\r\n| ftp server   | 连接到ftp服务器  |\r\n| get filename | 从ftp获取文件    |\r\n| lcd ~        | 切换本机接收目录 |\r\n\r\n### wget\r\n\r\n> 下载网络上的东西\r\n\r\n### ssh\r\n\r\n> 服务器重装后，key会改变\r\n>\r\n> 要想再次连接\r\n>\r\n> 需要删除`~/.ssh/know_hosts`\r\n\r\n### scp\r\n\r\n> `scp usr@server:filename yourfile`\r\n\r\n## New\r\n\r\n```bash\r\nip addr|route|link\r\nss\r\n```\r\n\r\n## Old\r\n\r\n```bash\r\n# 网络配置\r\nifconfig <name> up|down\r\nifdown|up <device_name>\r\nifconfig <device_name> <ip_addr>\r\nnetstat\r\n# 路由\r\nroute -n \r\n```\r\n\r\n\r\n\r\n## 配置文件\r\n\r\n> `/etc/udev/rules.d/file`: 网卡\r\n\r\n```bash\r\ndmesg | grep -i dev\r\n```\r\n\r\n"}}]);